+
+/** A condition accepted by the conditional option helpers. */
+export type OptionCondition =
+  | string
+  | OptionDependencyCondition
+  | Pick<OptionDependency, "anyOf" | "allOf">;
+
+function normalizeOptionCondition(condition: OptionCondition | OptionDependency): OptionDependency {
+  if (typeof condition === "string") return { option: condition };
+  return condition;
+}
+
+/**
+ * Creates an option which reports a validation error unless its condition is met.
+ * @since 0.10.0
+ */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition | OptionDependency,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = Array.isArray(flagSpec) ? flagSpec : [flagSpec];
+  const dependsOn = { ...normalizeOptionCondition(condition), required: true };
+  return valueParser == null
+    ? option(...names, { dependsOn })
+    : option(...names, valueParser, { dependsOn });
+}
+
+/**
+ * Creates an option that is hidden while its condition is not met.
+ * @since 0.10.0
+ */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition | OptionDependency,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = Array.isArray(flagSpec) ? flagSpec : [flagSpec];
+  const dependsOn = normalizeOptionCondition(condition);
+  return valueParser == null
+    ? option(...names, { dependsOn })
+    : option(...names, valueParser, { dependsOn });
+}
+
+/**
+ * Creates an option controlled by a conditional dependency configuration.
+ * @since 0.10.0
+ */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition | OptionDependency,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return optionalWhen(condition, flagSpec, valueParser);
+}
