+/** Returns the option term nested in a parser's usage, preserving wrapper metadata. */
+function findOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term;
+    if (term.type === "optional" || term.type === "multiple") {
+      const found = findOptionTerm(term.terms);
+      if (found) return found;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const found = findOptionTerm(terms);
+        if (found) return found;
+      }
+    }
+  }
+  return undefined;
+}
+
+function unwrapOptionState(state: unknown): { readonly provided: boolean; readonly value: unknown } {
+  if (Array.isArray(state) && state.length === 1) return unwrapOptionState(state[0]);
+  if (isDependencySourceState(state)) return unwrapOptionState(state.result);
+  if (state && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: boolean; readonly value?: unknown };
+    return result.success ? { provided: true, value: result.value } : { provided: false, value: undefined };
+  }
+  return { provided: state !== undefined, value: state };
+}
+
+interface ObjectOptionDependencyContext {
+  readonly terms: ReadonlyMap<string | symbol, Extract<UsageTerm, { type: "option" }>>;
+  readonly names: ReadonlyMap<string, string | symbol>;
+}
+
+function evaluateOptionDependency(
+  dependency: NonNullable<Extract<UsageTerm, { type: "option" }>["dependsOn"]>,
+  state: Record<string | symbol, unknown>,
+  context: ObjectOptionDependencyContext,
+): { readonly satisfied: boolean; readonly explicitlyFalsy: boolean; readonly errorName: string; readonly expected?: unknown } {
+  const check = (condition: { readonly option: string; readonly value?: unknown }) => {
+    const key = (condition.option in state || context.terms.has(condition.option))
+      ? condition.option
+      : context.names.get(condition.option);
+    const term = key == null ? undefined : context.terms.get(key);
+    const result = key == null ? { provided: false, value: undefined } : unwrapOptionState(state[key]);
+    const satisfied = "value" in condition
+      ? result.value === condition.value
+      : Boolean(result.value);
+    return {
+      satisfied,
+      explicitlyFalsy: result.provided && !Boolean(result.value),
+      errorName: term?.names[0] ?? condition.option,
+      expected: condition.value,
+    };
+  };
+  const conditions = dependency.anyOf ?? dependency.allOf ??
+    (dependency.option == null ? [] : [{ option: dependency.option, ...("value" in dependency && { value: dependency.value })]);
+  const results = conditions.map(check);
+  const satisfied = dependency.anyOf != null
+    ? results.some((result) => result.satisfied)
+    : results.every((result) => result.satisfied);
+  const failed = results.find((result) => !result.satisfied) ?? results[0];
+  return {
+    satisfied,
+    explicitlyFalsy: !satisfied && (failed?.explicitlyFalsy ?? false),
+    errorName: failed?.errorName ?? dependency.option ?? "unknown",
+    expected: failed?.expected,
+  };
+}
+
+function dependencyError(
+  dependent: Extract<UsageTerm, { type: "option" }>,
+  dependency: ReturnType<typeof evaluateOptionDependency>,
+): Message {
+  const expected = dependency.expected === undefined
+    ? ""
+    : ` with value ${String(dependency.expected)}`;
+  return message`Option ${eOptionName(dependent.names[0])} requires option ${eOptionName(dependency.errorName)}${expected}.`;
+}
